using System;
using System.Collections.Generic;

public class Solution {
    public List<List<int>> permutations(int[] data) {
        List<List<int>> result = new List<List<int>>();
        GeneratePermutations(data, 0, result);
        return result;
    }

    private void GeneratePermutations(int[] data, int start, List<List<int>> result) {
        if (start >= data.Length) {
            result.Add(new List<int>(data));
            return;
        }
        for (int i = start; i < data.Length; i++) {
            Swap(data, start, i);
            GeneratePermutations(data, start + 1, result);
            Swap(data, start, i); // backtrack
        }
    }

    private void Swap(int[] data, int i, int j) {
        int temp = data[i];
        data[i] = data[j];
        data[j] = temp;
    }
}

