import java.util.ArrayList;
import java.util.List;
class Solution {
    public List<List<Integer>> permutations(int[] data) {
        List<List<Integer>> result = new ArrayList<>();
        boolean[] used = new boolean[data.length];
        backtrack(data, used, new ArrayList<>(), result);
        return result;
    }
    private void backtrack(int[] data, boolean[] used, List<Integer> current, List<List<Integer>> result) {
        if (current.size() == data.length) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (int i = 0; i < data.length; i++) {
            if (!used[i]) {
                used[i] = true;
                current.add(data[i]);
                backtrack(data, used, current, result);
                current.remove(current.size() - 1);
                used[i] = false;
            }
        }
    }
}

